// Este nodo 'function' transforma cada fila de la consulta MSSQL
// en un mensaje que el nodo mysql-r2 puede usar para una inserción preparada.

const mssqlRows = msg.payload; // msg.payload es un array de objetos de la consulta MSSQL

if (!Array.isArray(mssqlRows) || mssqlRows.length === 0) {
    node.warn("No se recibieron filas desde la consulta MSSQL.");
    return null; // Detiene el flujo si no hay datos
}

const mysqlMessages = []; // Array para almacenar los mensajes que se enviarán al nodo MySQL

// Definir la consulta INSERT con placeholders para MySQL
// ¡CAMBIO AQUÍ: Agregado 'IGNORE' después de 'INSERT'!
const insertSql = `
    INSERT IGNORE INTO detalle_oc (nro_oc, numero_item, codigo, articulo, cantidad, uni_med, pu, total_item, fecha_entrega)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
`;

// Iterar sobre cada fila recibida de MSSQL
for (const row of mssqlRows) {
    // Mapear los nombres de columna de MSSQL a las variables PHP.
    // Asegúrate de que estos nombres coincidan con los alias en tu consulta MSSQL.
    const nro_oc = row.OC;
    const numero_item = row.NUMEROITEM;
    const codigo = row.CODIGO;
    const articulo = row.ARTICULO;
    const cantidad = row.CANTIDAD;
    const uni_med = row.UNI_MED;
    const pu = row.PU;
    const total_item = row.TOTAL_ITEM;
    let fecha_entrega = row.fechaentrega;

    // **IMPORTANTE:** Formatear la fecha para MySQL.
    // Los nodos de base de datos a menudo devuelven fechas como objetos Date de JS o strings ISO.
    if (fecha_entrega instanceof Date) {
        fecha_entrega = fecha_entrega.toISOString().slice(0, 19).replace('T', ' ');
    } else if (typeof fecha_entrega === 'string' && fecha_entrega.includes('T')) {
        fecha_entrega = fecha_entrega.slice(0, 19).replace('T', ' ');
    }

    // Crear el array de parámetros en el ORDEN CORRECTO para la consulta preparada
    const params = [
        nro_oc,
        numero_item,
        codigo,
        articulo,
        cantidad,
        uni_med,
        pu,
        total_item,
        fecha_entrega
    ];

    // Crear un nuevo mensaje para el nodo MySQL
    mysqlMessages.push({
        payload: params,
        topic: insertSql
    });
}

// Devolver un array de mensajes. Cada mensaje será enviado secuencialmente al siguiente nodo.
return [mysqlMessages];

